#graphql
mutation SegmentCreateBlankName($name: String!, $query: String!) {
  segmentCreate(name: $name, query: $query) {
    segment { id name query creationDate lastEditDate }
    userErrors { field message }
  }
}

#graphql
mutation SegmentCreateInvalidQuery($name: String!, $query: String!) {
  segmentCreate(name: $name, query: $query) {
    segment { id name query creationDate lastEditDate }
    userErrors { field message }
  }
}

#graphql
mutation SegmentUpdateUnknownId($id: ID!, $name: String) {
  segmentUpdate(id: $id, name: $name) {
    segment { id name query creationDate lastEditDate }
    userErrors { field message }
  }
}

#graphql
mutation SegmentDeleteUnknownId($id: ID!) {
  segmentDelete(id: $id) {
    deletedSegmentId
    userErrors { field message }
  }
}
